import { FalseFlag as ff } from "@falseflag/config";

export default ff.flag({
  value_type: "string",
  default: "basic",
  rules: [
    ff.rule(
      "us-pro",
      ff.all(
        ff.cel("ctx.user.plan == 'pro'"),
        ff.eq("user.region", "us"),
      ),
      "premium",
    ),
  ],
});
